import React, { Component, Fragment } from "react";
import { Navbar, Nav, NavDropdown } from "react-bootstrap";

export class NavigationBar extends Component {
	state = {
		currentUser: this.props.currentUser,
	};
	render() {
		return (
			<div>
				<Navbar bg="light" expand="lg">
					<Navbar.Brand href="#home">
						Házi feladat nyilvántartó
					</Navbar.Brand>
					<Navbar.Toggle aria-controls="basic-navbar-nav" />
					<Navbar.Collapse id="basic-navbar-nav">
						<Nav className="mr-auto">
							<Nav.Link href="/index">Főoldal</Nav.Link>
							<Nav.Link href="/hozzaadas">Hozzáadás</Nav.Link>
							<NavDropdown
								title="Módosítás"
								id="basic-nav-dropdown"
							>
								<NavDropdown.Item href="/modositas">
									Módosítás
								</NavDropdown.Item>
								<NavDropdown.Divider />
								<NavDropdown.Item href="/modositasuser">
									Módosítás Jelenlegi
								</NavDropdown.Item>
							</NavDropdown>
							<Nav.Link href="/masolas">Másolás</Nav.Link>
							<Nav.Link href="/torles">Törlés</Nav.Link>
							<NavDropdown
								title="Fiók kezelés"
								id="basic-nav-dropdown"
							>
								{this.state.currentUser === "osztály" ? (
									<Fragment>
										<NavDropdown.Item href="/login">
											Bejelentkezés
										</NavDropdown.Item>
										<NavDropdown.Divider />
										<NavDropdown.Item href="/register">
											Regisztráció
										</NavDropdown.Item>
									</Fragment>
								) : (
									<Fragment>
										<NavDropdown.Item href="/logout">
											Kijelentkezés
										</NavDropdown.Item>
									</Fragment>
								)}
							</NavDropdown>
						</Nav>
					</Navbar.Collapse>
				</Navbar>
			</div>
		);
	}
}

export default NavigationBar;
