/* eslint-disable no-unused-expressions */
import React, { Component } from "react";
import Cookies from "js-cookie";
import { Redirect } from "react-router-dom";

export class Login extends Component {
	state = {
		error: "",
		username: "",
		password: "",
		done: false,
	};
	handleUserChange = (e) => {
		this.setState({
			username: e.target.value,
		});
	};
	handlePassChange = (e) => {
		this.setState({
			password: e.target.value,
		});
	};
	handleSubmit = (e) => {
		e.preventDefault();
		if (this.state.username !== "" && this.state.password !== "") {
			let requestOption = {
				method: "POST",
				headers: { "Content-Type": "application/json" },
				body: JSON.stringify({
					username: this.state.username,
					password: this.state.password,
				}),
			};
			console.log(requestOption);
			fetch("http://tomimedia.duckdns.org:3002/authLogin", requestOption)
				.then((res) => res.json())
				.then((databack) => {
					if (databack.login === "failed") {
						this.setState({
							error: databack.error,
							username: "",
							password: "",
						});
					} else {
						Cookies.set("UsrId", databack.accessToken);
						this.setState({
							error: "",
							username: "",
							password: "",
							done: true,
						});
					}
				});
		} else {
			this.setState({
				error: "Nem adtál meg felhasználónevet vagy jelszót!",
				username: "",
				password: "",
			});
		}
	};
	componentDidMount = () => {
		if (this.props.location.state) {
			this.setState({
				error: this.props.location.state.error,
			});
		}
	};
	render() {
		console.log(this.state.error);
		return (
			<div>
				{this.state.done !== true ? (
					<div className="container-fluid">
						<div className="row">
							<div className="col-md-3 col-sm-12"></div>
							<div className="col-md-6 col-sm-12">
								{this.state.error !== "" ? (
									<h4 className="mt-5 text-danger">
										{this.state.error}
									</h4>
								) : (
									""
								)}
								<form onSubmit={this.handleSubmit}>
									<div className="form-group">
										<label htmlFor="uname" className="mt-2">
											Felhasználónév
										</label>
										<input
											type="text"
											name="uname"
											id="uname"
											placeholder="Felhasználónév"
											autoComplete="off"
											onChange={this.handleUserChange}
											value={this.state.username}
											className="form-control bg-light"
										/>
										<label htmlFor="pwd" className="mt-1">
											Jelszó
										</label>
										<input
											type="password"
											name="pwd"
											id="pwd"
											placeholder="Jelszó"
											autoComplete="off"
											onChange={this.handlePassChange}
											value={this.state.password}
											className="form-control bg-light"
										/>
										<input
											type="submit"
											className="btn btn-info mt-1"
										/>
									</div>
								</form>
								<a
									href="/forgotPassword"
									className="text-primary"
								>
									Elfelejtett Jelszó
								</a>
							</div>
							<div className="col-md-3 col-sm-12"></div>
						</div>
					</div>
				) : (
					<Redirect to="/" />
				)}
			</div>
		);
	}
}

export default Login;
