import React, { Component } from "react";

class Teszt extends Component {
	state = {
		currentUser: "",
	};
	componentDidMount = () => {
		fetch("http://localhost:3002/getCurrentUser")
			.then((res) => res.json())
			.then((data) => {
				console.log(data);
			});
	};
	handleSubmit = (e) => {
		e.preventDefault();
		let requestOption = {
			method: "POST",
			headers: { "Content-Type": "application/json" },
			body: JSON.stringify({
				username: "Németh Tamás",
				password: "n0527b0113V",
			}),
		};
		fetch("http://localhost:3002/login", requestOption)
			.then((res) => res.json())
			.then((data) => {
				console.log(data);
				let requestOption2 = {
					headers: {
						"Access-Token": data.accessToken,
					},
				};
				fetch("http://localhost:3002/getCurrentUser", requestOption2)
					.then((res2) => res2.json())
					.then((data2) => {
						console.log(data2);
					});
			});
	};
	render() {
		return (
			<div>
				{this.state.currentUser !== "" ? (
					<h1>Szia {this.state.currentUser}</h1>
				) : (
					<h1>Jelenkezz be</h1>
				)}
				<form onSubmit={this.handleSubmit}>
					<input type="submit" value="Bejelentkezés" />
				</form>
			</div>
		);
	}
}

export default Teszt;
